"use strict";(self.webpackChunkheiman_wiki_public=self.webpackChunkheiman_wiki_public||[]).push([["6300"],{49(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"welcome","metadata":{"permalink":"/heiman-wiki-public/de/blog/welcome","source":"@site/i18n/de/docusaurus-plugin-content-blog/2021-08-26-welcome/index.mdx","title":"Willkommen beim Heiman Technology Wiki","description":"Willkommen beim Heiman Technology Wiki! Dies ist die offizielle Wissensdatenbank von Heiman Technology mit Produktdokumentationen, technischen L\xf6sungen, Branchennachrichten und Unternehmensinformationen.","date":"2021-08-26T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/de/blog/tags/heiman","description":"Heiman Technology Neuigkeiten und Updates"}],"readingTime":0.68,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/de/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"welcome","title":"Willkommen beim Heiman Technology Wiki","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"nextItem":{"title":"Heiman Matter Smart Smoke Alarm offiziell gestartet","permalink":"/heiman-wiki-public/de/blog/mdx-blog-post"}},"content":"Willkommen beim Heiman Technology Wiki! Dies ist die offizielle Wissensdatenbank von Heiman Technology mit Produktdokumentationen, technischen L\xf6sungen, Branchennachrichten und Unternehmensinformationen.\\n\\n{/* truncate */}\\n\\n## \xdcber diese Seite\\n\\nDas Heiman Technology Wiki bietet Partnern, Entwicklern und Kunden eine zentrale Anlaufstelle f\xfcr technische Ressourcen und hilft Ihnen, Folgendes schnell zu verstehen:\\n\\n- **Produktzentrum** \u2014 Intelligenter Brandschutz, intelligente Gassicherheit, intelligente Seniorenbetreuung und intelligente Sensorik\\n- **L\xf6sungen** \u2014 Branchenweite intelligente Sicherheitsl\xf6sungen\\n- **Technische Dokumentation** \u2014 API-Anbindungsleitfaden, SDK-Nutzungshinweise, Installations- und Bereitstellungshandb\xfccher\\n- **Brancheneinblicke** \u2014 Aktuelle Trends und politische Analysen im Bereich intelligente Sicherheit\\n\\n## Schnellnavigation\\n\\n- Besuchen Sie [Produkte & L\xf6sungen](/docs/tutorial-basics/create-a-page) f\xfcr Informationen zu den Heiman-Produktlinien\\n- Lesen Sie die [Unternehmensvorstellung](/docs/intro) f\xfcr die Geschichte von Heiman\\n- Besuchen Sie die [Heiman-Website](https://www.heiman.com.cn) f\xfcr weitere Informationen\\n\\nBei Fragen wenden Sie sich bitte an unsere Service-Hotline **400-8959-500** oder nutzen Sie den Online-Kundendienst."},{"id":"mdx-blog-post","metadata":{"permalink":"/heiman-wiki-public/de/blog/mdx-blog-post","source":"@site/i18n/de/docusaurus-plugin-content-blog/2021-08-01-mdx-blog-post.mdx","title":"Heiman Matter Smart Smoke Alarm offiziell gestartet","description":"Der neue Heiman Smart Smoke Alarm HS1SA-M mit Matter-Protokoll wurde offiziell vorgestellt. Es ist eines der ersten Rauchmelderprodukte der Branche, das die Matter 1.2-Zertifizierung erhalten hat.","date":"2021-08-01T00:00:00.000Z","tags":[{"inline":false,"label":"Matter","permalink":"/heiman-wiki-public/de/blog/tags/matter","description":"Matter-Protokoll"},{"inline":false,"label":"Intelligenter Brandschutz","permalink":"/heiman-wiki-public/de/blog/tags/smart-fire","description":"Produkte und L\xf6sungen f\xfcr intelligenten Brandschutz"}],"readingTime":0.65,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/de/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"mdx-blog-post","title":"Heiman Matter Smart Smoke Alarm offiziell gestartet","authors":["heiman"],"tags":["matter","smart-fire"]},"unlisted":false,"prevItem":{"title":"Willkommen beim Heiman Technology Wiki","permalink":"/heiman-wiki-public/de/blog/welcome"},"nextItem":{"title":"Meilensteine von Heiman Technology","permalink":"/heiman-wiki-public/de/blog/long-blog-post"}},"content":"Der neue Heiman Smart Smoke Alarm HS1SA-M mit Matter-Protokoll wurde offiziell vorgestellt. Es ist eines der ersten Rauchmelderprodukte der Branche, das die Matter 1.2-Zertifizierung erhalten hat.\\n\\n{/* truncate */}\\n\\n:::tip\\n\\nDer HS1SA-M unterst\xfctzt die vier wichtigsten Smart-Home-\xd6kosysteme: Apple HomeKit, Amazon Alexa, Google Home und Samsung SmartThings.\\n\\n:::\\n\\n## Kernfunktionen\\n\\n- **Matter 1.2-Zertifizierung** \u2013 Erm\xf6glicht ger\xe4te- und plattform\xfcbergreifende Interoperabilit\xe4t\\n- **Fotoelektrische Raucherkennung** \u2013 Schnelle Reaktion auf verschiedene Brandraucharten\\n- **Sprachalarm** \u2013 Mehrere Sprachoptionen, klare Gefahrenmeldung\\n- **Selbsttestfunktion** \u2013 Regelm\xe4\xdfige Selbsttests zur Sicherstellung des ordnungsgem\xe4\xdfen Betriebs\\n- **Fernbenachrichtigung** \u2013 Echtzeit-Push-Benachrichtigungen \xfcber die mobile APP\\n\\n## Kompatibilit\xe4t\\n\\nDer HS1SA-M kann nahtlos in g\xe4ngige Smart-Home-Plattformen integriert werden. Benutzer k\xf6nnen das Ger\xe4t direkt \xfcber ihr Smartphone steuern und verwalten, ohne dass ein zus\xe4tzliches Gateway erforderlich ist.\\n\\nWeitere Informationen finden Sie im [Produktzentrum](/docs/tutorial-basics/create-a-page)."},{"id":"long-blog-post","metadata":{"permalink":"/heiman-wiki-public/de/blog/long-blog-post","source":"@site/i18n/de/docusaurus-plugin-content-blog/2019-05-29-long-blog-post.mdx","title":"Meilensteine von Heiman Technology","description":"Seit der Gr\xfcndung im Jahr 2005 hat Heiman Technology eine \xfcber 20-j\xe4hrige Entwicklungsgeschichte hinter sich. Dieser Artikel nimmt Sie mit auf einen R\xfcckblick auf die wichtigsten Meilensteine von Heiman.","date":"2019-05-29T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/de/blog/tags/heiman","description":"Heiman Technology Neuigkeiten und Updates"}],"readingTime":1.22,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/de/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"long-blog-post","title":"Meilensteine von Heiman Technology","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Heiman Matter Smart Smoke Alarm offiziell gestartet","permalink":"/heiman-wiki-public/de/blog/mdx-blog-post"},"nextItem":{"title":"Heiman Technology als nationales \\"Kleiner Riese\\"-Unternehmen ausgezeichnet","permalink":"/heiman-wiki-public/de/blog/first-blog-post"}},"content":"Seit der Gr\xfcndung im Jahr 2005 hat Heiman Technology eine \xfcber 20-j\xe4hrige Entwicklungsgeschichte hinter sich. Dieser Artikel nimmt Sie mit auf einen R\xfcckblick auf die wichtigsten Meilensteine von Heiman.\\n\\n{/* truncate */}\\n\\n## 2005 \u2013 Gr\xfcndung\\n\\nDie Shenzhen Heiman Technology Co., Ltd. wird offiziell gegr\xfcndet und beginnt ihre T\xe4tigkeit im Bereich Sicherheitssensorik.\\n\\n## 2006 \u2013 Internationaler Start\\n\\nMehrere Produkte erhalten die EU-CE-Zertifizierung und eine Zusammenarbeit mit China Mobile wird vereinbart.\\n\\n## 2011 \u2013 Internationaler Zertifizierungsdurchbruch\\n\\nMehrere Produkte erhalten die EU-Zertifizierungen EN54-7 und EN14604, was die internationale Spitzenqualit\xe4t der Produkte belegt.\\n\\n## 2012 \u2013 Wandel zum Smart Home\\n\\nDas Smart-Home-Projekt wird vollst\xe4ndig gestartet. Heiman wandelt sich zu einem Unternehmen, das sich auf die Entwicklung, Produktion und den Vertrieb von Smart-Home-Produkten konzentriert.\\n\\n## 2017 \u2013 Bedeutender Durchbruch\\n\\n- Entwicklung des ersten NB-IoT-Rauchmelders in China\\n- Auszeichnung mit 2 Red Dot Design Awards\\n- MFi-Zertifizierung und Qualifikation als Apple-Hersteller\\n\\n## 2020 \u2013 Kapitalinvestition\\n\\nAbschluss der Serie-A-Finanzierung durch die Shenzhen Hi-tech Investment Group. Erhalt der Auszeichnung \u201ESpezialisiertes und neues Unternehmen der Provinz Guangdong\\".\\n\\n## 2022 \u2013 Nationale Anerkennung\\n\\nAuszeichnung als nationales spezialisiertes und neues \u201EKleiner Riese\\"-Unternehmen. Die K1-Serie erh\xe4lt den Red Dot Design Award.\\n\\n## 2023 \u2013 Internationaler Standardf\xfchrer\\n\\nDas Heiman-Pr\xfcflabor erh\xe4lt offiziell die nationale CNAS-Akkreditierung. Rauchmelder und CO-Melder erhalten als erste die Matter 1.2-Zertifizierung.\\n\\n## 2024 \u2013 Bis heute\\n\\nKontinuierliche Innovation und Vertiefung in den vier Kernbereichen intelligenter Brandschutz, intelligente Gassicherheit, intelligente Seniorenbetreuung und intelligente Sensoren. Belieferung von Kunden in \xfcber 100 L\xe4ndern mit hochwertigen Produkten und Dienstleistungen."},{"id":"first-blog-post","metadata":{"permalink":"/heiman-wiki-public/de/blog/first-blog-post","source":"@site/i18n/de/docusaurus-plugin-content-blog/2019-05-28-first-blog-post.mdx","title":"Heiman Technology als nationales \\"Kleiner Riese\\"-Unternehmen ausgezeichnet","description":"Im Jahr 2022 wurde Heiman Technology aufgrund seiner tiefgreifenden technologischen Expertise und Innovationsf\xe4higkeit im Bereich intelligenter Sensortechnologien offiziell als nationales spezialisiertes und neues \u201EKleiner Riese\\"-Unternehmen ausgezeichnet.","date":"2019-05-28T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/de/blog/tags/heiman","description":"Heiman Technology Neuigkeiten und Updates"}],"readingTime":0.48,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/de/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"first-blog-post","title":"Heiman Technology als nationales \\"Kleiner Riese\\"-Unternehmen ausgezeichnet","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Meilensteine von Heiman Technology","permalink":"/heiman-wiki-public/de/blog/long-blog-post"}},"content":"Im Jahr 2022 wurde Heiman Technology aufgrund seiner tiefgreifenden technologischen Expertise und Innovationsf\xe4higkeit im Bereich intelligenter Sensortechnologien offiziell als nationales spezialisiertes und neues \u201EKleiner Riese\\"-Unternehmen ausgezeichnet.\\n\\n{/* truncate */}\\n\\nDiese nationale Anerkennung w\xfcrdigt die hohe Spezialisierung, Pr\xe4zision, Einzigartigkeit und Innovationskraft von Heiman Technology. Heiman wird weiterhin in den Bereichen intelligenter Brandschutz, intelligente Gassicherheit, intelligente Seniorenbetreuung und intelligente Sensoren t\xe4tig sein und seinen Kunden weiterhin hochwertige Produkte und Dienstleistungen bieten.\\n\\nZuvor hatte Heiman Technology bereits mehrere wichtige Auszeichnungen erhalten, darunter den Status eines nationalen Hightech-Unternehmens und die Anerkennung als spezialisiertes und neues Unternehmen der Provinz Guangdong."}]}}')}}]);